const _h = this.helpers;
const fetch = async (url, init = {}) => {
  const opts = { method: init.method || 'GET', url, headers: { ...(init.headers || {}) }, json: true, timeout: 10000, returnFullResponse: false };
  if (opts.headers['Content-Type']) delete opts.headers['Content-Type'];
  if (opts.headers['content-type']) delete opts.headers['content-type'];
  if (init.body !== undefined) {
    if (typeof init.body === 'string') { try { opts.body = JSON.parse(init.body); } catch { opts.body = init.body; } }
    else opts.body = init.body;
  }
  try {
    const data = await _h.httpRequest(opts);
    return { ok: true, status: 200, json: async () => data, text: async () => (typeof data === 'string' ? data : JSON.stringify(data)) };
  } catch (e) {
    const status = (e && e.statusCode) || (e && e.response && e.response.statusCode) || (e && e.cause && e.cause.statusCode) || 500;
    let errBody = (e && e.response && e.response.body) ?? (e && e.cause && e.cause.body) ?? null;
    if (errBody && typeof errBody !== 'string') { try { errBody = JSON.stringify(errBody); } catch { errBody = String(errBody); } }
    if (!errBody && e && e.message) errBody = e.message;
    return { ok: false, status, json: async () => { try { return JSON.parse(errBody); } catch { return errBody; } }, text: async () => String(errBody) };
  }
};

const _SUPABASE_URL = $vars.CARGLASS_SUPABASE_URL;
const _SUPABASE_KEY = $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY;
const _SB_HEADERS = { apikey: _SUPABASE_KEY, Authorization: 'Bearer ' + _SUPABASE_KEY };
async function resolveConvId(input) {
  if (!input) return null;
  if (/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(String(input))) return input;
  try {
    const r1 = await fetch(`${_SUPABASE_URL}/rest/v1/calls?external_call_id=eq.${encodeURIComponent(input)}&select=id&limit=1`, { headers: _SB_HEADERS });
    if (!r1.ok) return null;
    const calls = await r1.json();
    if (!calls.length) return null;
    const r2 = await fetch(`${_SUPABASE_URL}/rest/v1/conversations?call_id=eq.${calls[0].id}&select=id&limit=1`, { headers: _SB_HEADERS });
    if (!r2.ok) return null;
    const cv = await r2.json();
    return cv.length ? cv[0].id : null;
  } catch (e) { return null; }
}

const body = $input.first().json.body || {};
body.conversation_id = await resolveConvId(body.conversation_id);
const { new_start, confirmation_token, conversation_id } = body;
let appointment_id = body.appointment_id || body.booking_reference || body.booking_ref || '';
if (!appointment_id || !new_start || !confirmation_token) {
  return [{ json: { ok: false, error_code: 'CONFIRMATION_REQUIRED', message_for_agent: 'Bitte zuerst die neue Uhrzeit mit dem Kunden bestätigen.' } }];
}
const headers = {
  apikey: $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY,
  Authorization: 'Bearer ' + $vars.CARGLASS_SUPABASE_SERVICE_ROLE_KEY,
  'Prefer': 'return=representation',
};
const sb = $vars.CARGLASS_SUPABASE_URL;
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const lookupKey = UUID_RE.test(String(appointment_id)) ? 'id' : 'booking_reference';
const getR = await fetch(`${sb}/rest/v1/appointments?${lookupKey}=eq.${encodeURIComponent(appointment_id)}&select=id,booking_reference,scheduled_start,scheduled_end,status,service_id,services(default_duration_minutes)`, { headers });
if (!getR.ok) return [{ json: { ok: false, error_code: 'NOT_FOUND', message_for_agent: 'Termin nicht gefunden.' } }];
const rows = await getR.json();
if (!rows.length) return [{ json: { ok: false, error_code: 'NOT_FOUND', message_for_agent: 'Termin nicht gefunden.' } }];
const current = rows[0];
appointment_id = current.id;
const durMin = current.services ? current.services.default_duration_minutes : 90;
const newEnd = new Date(new Date(new_start).getTime() + durMin * 60000).toISOString();
const upd = await fetch(`${sb}/rest/v1/appointments?id=eq.${appointment_id}`, {
  method: 'PATCH', headers,
  body: { scheduled_start: new_start, scheduled_end: newEnd, status: 'scheduled' },
});
if (!upd.ok) return [{ json: { ok: false, error_code: 'UPDATE_FAILED', message_for_agent: 'Termin konnte nicht aktualisiert werden.' } }];
const updated = (await upd.json())[0];
await fetch(`${sb}/rest/v1/appointment_history`, {
  method: 'POST', headers,
  body: {
    appointment_id,
    previous_status: current.status,
    new_status: 'scheduled',
    previous_start: current.scheduled_start,
    new_start,
    changed_by: 'bot',
    conversation_id: conversation_id || null,
    reason: 'Rebooking via voicebot — confirmation_token: ' + confirmation_token,
  },
});
return [{ json: { ok: true, data: { appointment: {
  id: updated.id,
  booking_reference: updated.booking_reference,
  new_start: updated.scheduled_start,
  new_end: updated.scheduled_end,
  status: updated.status,
} } } }];
